using System;

static T Max<T>(T a, T b) where T : IComparable<T> =>
    a.CompareTo(b) >= 0 ? a : b;

class Program {
    static void Main() {
        Console.WriteLine(Max(3, 7));
        Console.WriteLine(Max("apple", "banana"));
        Console.WriteLine(Max(3.14, 2.72));
    }
}

using System;

class Box<T> {
    public T Value { get; set; }
    public Box(T value) { Value = value; }
    public override string ToString() => $"Box[{Value}]";
}

class Program {
    static void Main() {
        var intBox = new Box<int>(42);
        var strBox = new Box<string>("hello");
        Console.WriteLine(intBox);
        Console.WriteLine(strBox);
        Console.WriteLine(intBox.Value + 1);
    }
}

using System;
using System.Collections.Generic;

class MyStack<T> {
    private List<T> items = new();
    public void Push(T item) => items.Add(item);
    public T Pop() {
        if (items.Count == 0) throw new InvalidOperationException("Stack is empty");
        T top = items[^1];
        items.RemoveAt(items.Count - 1);
        return top;
    }
    public int Count => items.Count;
}

class Program {
    static void Main() {
        var stack = new MyStack<string>();
        stack.Push("a"); stack.Push("b"); stack.Push("c");
        while (stack.Count > 0)
            Console.Write(stack.Pop() + " ");
        Console.WriteLine();
    }
}

using System;

static T CreateAndInit<T>() where T : new() {
    return new T();
}

class Greeter {
    public string Greet() => "Hello from Greeter!";
}

class Program {
    static void Main() {
        var g = CreateAndInit<Greeter>();
        Console.WriteLine(g.Greet());
    }
}

using System;

class Pair<TFirst, TSecond> {
    public TFirst First { get; }
    public TSecond Second { get; }
    public Pair(TFirst f, TSecond s) { First = f; Second = s; }
    public override string ToString() => $"({First}, {Second})";
}

class Program {
    static void Main() {
        var p1 = new Pair<string, int>("age", 30);
        var p2 = new Pair<int, bool>(1, true);
        Console.WriteLine(p1);
        Console.WriteLine(p2);
    }
}

using System;

static T GetOrDefault<T>(T[] arr, int index) {
    if (index < 0 || index >= arr.Length)
        return default(T);
    return arr[index];
}

class Program {
    static void Main() {
        int[] nums = { 10, 20, 30 };
        Console.WriteLine(GetOrDefault(nums, 1));  // 20
        Console.WriteLine(GetOrDefault(nums, 99)); // 0 (default int)
        string[] strs = { "hello" };
        Console.WriteLine(GetOrDefault(strs, 5) ?? "null"); // null -> "null"
    }
}

using System;
using System.Collections.Generic;

class Repository<T> {
    private List<T> store = new();
    public void Add(T item) => store.Add(item);
    public int Count => store.Count;
    public T Get(int index) => store[index];
}

class Product { public string Name { get; set; } }

class Program {
    static void Main() {
        var repo = new Repository<Product>();
        repo.Add(new Product { Name = "Widget" });
        repo.Add(new Product { Name = "Gadget" });
        Console.WriteLine($"{repo.Count} products");
        Console.WriteLine(repo.Get(0).Name);
    }
}

using System;
using System.Collections.Generic;

class Animal { public string Name { get; set; } }
class Dog : Animal {}

class Program {
    static void Main() {
        List<Dog> dogs = new() {
            new Dog { Name = "Rex" },
            new Dog { Name = "Buddy" }
        };
        IEnumerable<Animal> animals = dogs; // covariant!
        foreach (var a in animals)
            Console.WriteLine(a.Name);
    }
}
